import React, { useState } from 'react';
import toast from 'react-hot-toast';
import VideoTable from '../components/VideoTable';
import DailyViewsChart from '../components/DailyViewsChart';
import TopCreatorsChart from '../components/TopCreatorsChart';
import { triggerScrape } from '../services/api';

const TABS = [
  { id: 'working', label: "What's Working", icon: '🚀' },
  { id: 'why', label: 'Why It Works', icon: '🧠' },
  { id: 'creators', label: 'Creators', icon: '👤' },
  { id: 'actions', label: 'Actions', icon: '⚡' },
];

export default function Dashboard() {
  const [scraping, setScraping] = useState(false);
  const [activeTab, setActiveTab] = useState('working');

  const handleScrapeNow = async () => {
    setScraping(true);
    try {
      const res = await triggerScrape();
      toast.success(`Scraped ${res.data.scraped} videos`);
      setTimeout(() => window.location.reload(), 1500);
    } catch (err) {
      toast.error(err.response?.data?.error || 'Scrape failed');
    } finally {
      setScraping(false);
    }
  };

  return (
    <div>
      <div className="page-header">
        <h1>Dashboard</h1>
        <button
          className="btn btn-primary"
          disabled={scraping}
          onClick={handleScrapeNow}
        >
          {scraping ? 'Scraping…' : 'Scrape Now'}
        </button>
      </div>

      <div className="dashboard-tabs">
        <div className="dashboard-tabs-bar" role="tablist">
          {TABS.map((tab) => (
            <button
              key={tab.id}
              type="button"
              role="tab"
              aria-selected={activeTab === tab.id}
              className={`dashboard-tab ${activeTab === tab.id ? 'active' : ''}`}
              onClick={() => setActiveTab(tab.id)}
            >
              <span className="dashboard-tab-icon" aria-hidden>
                {tab.icon}
              </span>
              {tab.label}
            </button>
          ))}
        </div>

        <div className="dashboard-tab-panels">
          {activeTab === 'working' && (
            <section className="dashboard-tab-panel" aria-label="What's Working">
              <div className="charts-row">
                <DailyViewsChart />
                <TopCreatorsChart />
              </div>
            </section>
          )}

          {activeTab === 'why' && (
            <section className="dashboard-tab-panel placeholder-panel" aria-label="Why It Works">
              <div className="card">
                <p className="placeholder-panel-text">
                  Gemini-powered breakdowns will go here (hooks, formats, pacing).
                </p>
              </div>
            </section>
          )}

          {activeTab === 'creators' && (
            <section className="dashboard-tab-panel placeholder-panel" aria-label="Creators">
              <div className="card">
                <p className="placeholder-panel-text">
                  Creator-level insights and comparisons — ready for Gemini summaries.
                </p>
              </div>
            </section>
          )}

          {activeTab === 'actions' && (
            <section className="dashboard-tab-panel placeholder-panel" aria-label="Actions">
              <div className="card">
                <p className="placeholder-panel-text">
                  Recommended next steps — wire up Gemini for prioritized actions.
                </p>
              </div>
            </section>
          )}
        </div>
      </div>

      <VideoTable />
    </div>
  );
}
